import { NextResponse } from 'next/server';

interface CreatePostBody {
  title: string;
  content: string;
}

interface ApiPost {
  id: number;
  title: string;
  content: string;
  createdAt: string;
}

function isCreatePostBody(body: unknown): body is CreatePostBody {
  return (
    typeof body === 'object' &&
    body !== null &&
    'title' in body &&
    'content' in body &&
    typeof (body as Record<string, unknown>).title === 'string' &&
    typeof (body as Record<string, unknown>).content === 'string'
  );
}

export async function GET() {
  const posts: ApiPost[] = [
    { id: 1, title: 'First Post', content: 'This is the first post', createdAt: new Date().toISOString() },
    { id: 2, title: 'Second Post', content: 'This is the second post', createdAt: new Date().toISOString() },
  ];

  return NextResponse.json(posts);
}

export async function POST(req: Request) {
  const body: unknown = await req.json();

  if (!isCreatePostBody(body)) {
    return NextResponse.json({ error: 'Title and content are required' }, { status: 400 });
  }

  const newPost: ApiPost = {
    id: Date.now(),
    title: body.title,
    content: body.content,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(newPost, { status: 201 });
}

