import { cache } from 'react';

export interface JsonPlaceholderPost {
  userId: number;
  id: number;
  title: string;
  body: string;
}

export interface JsonPlaceholderComment {
  postId: number;
  id: number;
  name: string;
  email: string;
  body: string;
}

async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
  const response = await fetch(url, init);

  if (!response.ok) {
    throw new Error(`Request failed for ${url} with status ${response.status}`);
  }

  return response.json() as Promise<T>;
}

export const getRecentPosts = cache(async (limit = 5): Promise<JsonPlaceholderPost[]> => {
  return fetchJson<JsonPlaceholderPost[]>(
    `https://jsonplaceholder.typicode.com/posts?_limit=${limit}`,
  );
});

export const getAllPosts = cache(async (): Promise<JsonPlaceholderPost[]> => {
  return fetchJson<JsonPlaceholderPost[]>('https://jsonplaceholder.typicode.com/posts');
});

export const getPost = cache(async (id: string): Promise<JsonPlaceholderPost> => {
  return fetchJson<JsonPlaceholderPost>(`https://jsonplaceholder.typicode.com/posts/${id}`);
});

export const getPostComments = cache(async (id: string): Promise<JsonPlaceholderComment[]> => {
  return fetchJson<JsonPlaceholderComment[]>(
    `https://jsonplaceholder.typicode.com/posts/${id}/comments`,
  );
});

